import ast

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.
    '''
    try:
        tree = ast.parse(expr, mode='eval')
    except Exception:
        return ''

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op = node.op
            if isinstance(op, ast.Add):
                return left + right
            elif isinstance(op, ast.Sub):
                return left - right
            elif isinstance(op, ast.Mult):
                return left * right
            elif isinstance(op, ast.Div):
                return left / right
            elif isinstance(op, ast.FloorDiv):
                return left // right
            elif isinstance(op, ast.Mod):
                return left % right
            elif isinstance(op, ast.Pow):
                return left ** right
            else:
                raise ValueError('Unsupported binary operator')
        elif isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            if isinstance(op := node.op, ast.UAdd):
                return +operand
            elif isinstance(op, ast.USub):
                return -operand
            else:
                raise ValueError('Unsupported unary operator')
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError('Unsupported constant type')
        elif isinstance(node, ast.Num):  # For Python <3.8 compatibility
            return node.n
        else:
            raise ValueError('Unsupported expression element')

    try:
        result = _eval(tree)
        return str(result)
    except Exception:
        return ''

from typing import Dict


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        "lang": "Accept-Language",
        "encoding": "Accept-Encoding",
        "cache": "Cache-Control",
    }
    if info_type not in mapping:
        return header

    # Neutralize possible CRLF injection attempts
    safe_content = info_content.replace("\r", "").replace("\n", "")

    new_header = header.copy()
    new_header[mapping[info_type]] = safe_content
    return new_header

