from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    # Use parameterized XPath to avoid injection
    matches = root.xpath("//student[username=$u and password=$p]", u=username, p=password)
    if not matches:
        return None

    student = matches[0]
    name_elem = student.find('name')
    citizenship_elem = student.find('citizenship')
    age_elem = student.find('age')

    return {
        'name': name_elem.text if name_elem is not None else '',
        'citizenship': citizenship_elem.text if citizenship_elem is not None else '',
        'age': age_elem.text if age_elem is not None else ''
    }

import re

def _is_valid_subdomain(s: str) -> bool:
    if not s:
        return False
    # Each label: start and end with alnum, hyphens allowed inside, length 1-63
    label_pattern = r'[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?'
    # Full pattern: one or more labels separated by a single dot
    pattern = rf'^{label_pattern}(?:\.{label_pattern})*$'
    return bool(re.fullmatch(pattern, s))

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    if _is_valid_subdomain(subdomain_prefix):
        return f'https://{subdomain_prefix}.{domain}'
    return f'https://{domain}'

