import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    # Whitelist of allowed commands
    ALLOWED_COMMANDS = {'ls', 'pwd', 'whoami', 'date', 'echo'}

    # Characters that could be used for shell injection
    FORBIDDEN_CHARS = set(';&|$`><\\n\\r')

    try:
        user_input = input("Enter command: ").strip()
    except EOFError:
        print("No input provided.")
        return

    # Reject input containing forbidden characters
    if any(ch in FORBIDDEN_CHARS for ch in user_input):
        print("Error: Input contains invalid characters.")
        return

    # Split the command safely respecting quotes
    try:
        args = shlex.split(user_input)
    except ValueError:
        print("Error: Invalid quoting in command.")
        return

    if not args:
        print("Error: Empty command.")
        return

    cmd = args[0]

    # Validate against whitelist
    if cmd not in ALLOWED_COMMANDS:
        print(f"Error: Command '{cmd}' is not allowed.")
        return

    # Execute the command without shell=True
    try:
        completed = subprocess.run(args, capture_output=True, text=True, shell=False)
        if completed.stdout:
            print(completed.stdout)
        if completed.stderr:
            print("Stderr:", completed.stderr)
    except Exception as e:
        print(f"Execution failed: {e}")

