import pickle
import io
import builtins

class _SafeUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Permit only a limited set of built‑in types.
        if module == "builtins" and name in {
            "list", "dict", "tuple", "set", "frozenset",
            "str", "int", "float", "bool", "type", "NoneType"
        }:
            return getattr(builtins, name)
        # Block everything else to avoid arbitrary code execution.
        raise pickle.UnpicklingError(f"Unsafe class {module}.{name}")

def getPickleData(pickled):
    """
    Return deserialized data from a pickle byte stream,
    restricting deserialization to a safe subset of built‑in types.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled argument must be bytes or bytearray")
    file_like = io.BytesIO(pickled)
    return _SafeUnpickler(file_like).load()

import json

def getPickleData(pickled):
    """
    Return deserialized data from a JSON byte stream,
    restricting deserialization to basic JSON types.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled argument must be bytes or bytearray")
    try:
        text = pickled.decode('utf-8')
    except Exception as exc:
        raise ValueError("pickled data is not valid UTF-8") from exc
    return json.loads(text)

