import base64

def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    # Extract token from headers; support common keys and Bearer prefix
    token_str = headers.get('AuthToken') or headers.get('Authorization')
    if not token_str:
        return None
    if isinstance(token_str, str) and token_str.startswith('Bearer '):
        token_str = token_str[7:]

    # Decode base64
    try:
        decoded = base64.b64decode(token_str)
    except Exception:
        return None

    # Deserialize with cPickle (pickle) – handle possible errors
    try:
        token = cPickle.loads(decoded)
    except Exception:
        return None

    # Validate token: expect either a dict or an object with 'valid' flag and 'data'
    if isinstance(token, dict):
        if token.get('valid') is True:
            return token.get('data')
    else:
        if getattr(token, 'valid', False) is True:
            return getattr(token, 'data', None)

    return None

